import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [token, setToken] = useState(() => localStorage.getItem('dakkhana_token'));
  const [admin, setAdmin] = useState(() => {
    const stored = localStorage.getItem('dakkhana_admin');
    return stored ? JSON.parse(stored) : null;
  });

  useEffect(() => {
    if (token) {
      localStorage.setItem('dakkhana_token', token);
    } else {
      localStorage.removeItem('dakkhana_token');
    }
  }, [token]);

  useEffect(() => {
    if (admin) {
      localStorage.setItem('dakkhana_admin', JSON.stringify(admin));
    } else {
      localStorage.removeItem('dakkhana_admin');
    }
  }, [admin]);

  const login = (authToken, adminInfo) => {
    setToken(authToken);
    setAdmin(adminInfo);
  };

  const logout = () => {
    setToken(null);
    setAdmin(null);
  };

  const value = useMemo(
    () => ({ token, admin, login, logout, isAuthenticated: Boolean(token) }),
    [token, admin]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error('useAuth must be used inside AuthProvider');
  }
  return ctx;
}
